.darma-loader-uiverse-wild-orbit-rings {
  width: 180px;
  height: 180px;
  position: relative;
  display: flex;
  justify-content: center;
  align-items: center;
}
.darma-loader-uiverse-wild-orbit-rings__circle {
  width: 150px;
  height: 150px;
  border-radius: 52% 48% 58% 42%;
  border: 9px solid;
  position: absolute;
  box-sizing: border-box;
}
.darma-loader-uiverse-wild-orbit-rings__c1 { animation: darma-loader-uiverse-wild-orbit-rings-wildRingTurn 2.2s linear infinite; border-color: #ff9f1c; }
.darma-loader-uiverse-wild-orbit-rings__c2 { animation: darma-loader-uiverse-wild-orbit-rings-wildRingTurn 3s linear infinite reverse; border-color: var(--loader-color, #ff365e); }
.darma-loader-uiverse-wild-orbit-rings__c3 { animation: darma-loader-uiverse-wild-orbit-rings-wildRingTurn 2s linear infinite; border-color: #ffffff; opacity: .5; }
.darma-loader-uiverse-wild-orbit-rings__c4 { animation: darma-loader-uiverse-wild-orbit-rings-wildRingTurn 1s linear infinite reverse; border-color: var(--loader-secondary-color, #7dd3fc); opacity: .8; }
@keyframes darma-loader-uiverse-wild-orbit-rings-wildRingTurn { to { transform: rotate(360deg); } }

